<?php
namespace App\Http\Controllers;
use App\Models\Demande; use App\Models\Paiement; use Illuminate\Http\Request; use Illuminate\Support\Str;
class PaymentController extends Controller{public function pay(Demande $demande){return view('payments.pay',['demande'=>$demande]);} public function store(Request $r,Demande $demande){$r->validate(['moyen_paiement'=>'required|string|max:80']);$p=Paiement::create(['demande_id'=>$demande->id,'citoyen_id'=>$demande->citoyen_id,'montant'=>$demande->montant,'moyen_paiement'=>$r->moyen_paiement,'reference_transaction'=>'PAY-'.strtoupper(Str::random(10)),'statut'=>'paye','date_paiement'=>now()]);$demande->update(['statut'=>'deposee']);return redirect()->route('payments.receipt',$p);} public function receipt(Paiement $paiement){return view('payments.receipt',['paiement'=>$paiement]);}}
